// API Key authentication check - timing-safe comparison
const headers = $input.first().json.headers || {};

// Case-insensitive header lookup (defense against platform normalization changes)
const headerKeys = Object.keys(headers);
const apiKeyHeader = headerKeys.find(k => k.toLowerCase() === 'x-api-key');
const providedKey = apiKeyHeader ? headers[apiKeyHeader] : '';
const expectedKey = $env.LANGFLOW_API_KEY;

// Timing-safe comparison - prevents timing attacks on API key
function timingSafeEqual(a, b) {
  if (typeof a !== 'string' || typeof b !== 'string') return false;
  const MAX_LEN = 256;
  if (a.length > MAX_LEN || b.length > MAX_LEN) return false;

  // Early length check: prevents null-byte suffix attacks
  if (a.length !== b.length) return false;

  let result = 0;
  // Constant-time comparison: always iterate full length, no early exit
  for (let i = 0; i < a.length; i++) {
    result |= a.charCodeAt(i) ^ b.charCodeAt(i);
  }
  return result === 0;
}

if (expectedKey && !timingSafeEqual(providedKey || '', expectedKey)) {
  return [{ json: { valid: false, error: 'Authentication failed' } }];
}

const input = $input.first().json || {};
const flowId = input.flowId;
const inputs = input.inputs || {};
const stream = input.stream || false;
const flowName = input.flowName;
const logLevel = input.logLevel;
const tweaks = input.tweaks || {};
const refreshLangchainCache = input.refresh_langchain_cache || false;

// Validate flowId - alphanumeric, underscore, hyphen only (no path traversal)
const validFlowIdPattern = /^[a-zA-Z0-9_-]+$/;
if (!flowId || typeof flowId !== 'string' || !validFlowIdPattern.test(flowId)) {
  return [{ json: { valid: false, error: 'flowId is required and must be alphanumeric, underscore, or hyphen' } }];
}

// Validate flowId doesn't contain path traversal
if (flowId.includes('..') || flowId.includes('/') || flowId.includes('\\')) {
  return [{ json: { valid: false, error: 'Invalid flowId: path traversal detected' } }];
}

// Validate inputs is an object if provided
if (inputs && (typeof inputs !== 'object' || Array.isArray(inputs))) {
  return [{ json: { valid: false, error: 'inputs must be an object if provided' } }];
}

// Validate stream is a boolean if provided
if (stream !== undefined && typeof stream !== 'boolean') {
  return [{ json: { valid: false, error: 'stream must be a boolean if provided' } }];
}

// Validate flowName is a string if provided
if (flowName !== undefined && typeof flowName !== 'string') {
  return [{ json: { valid: false, error: 'flowName must be a string if provided' } }];
}

// Validate logLevel is one of the allowed values if provided
const validLogLevels = ['DEBUG', 'INFO', 'WARNING', 'ERROR', 'CRITICAL'];
if (logLevel !== undefined) {
  if (typeof logLevel !== 'string' || !validLogLevels.includes(logLevel.toUpperCase())) {
    return [{ json: { valid: false, error: 'logLevel must be one of: ' + validLogLevels.join(', ') } }];
  }
}

// Validate tweaks is an object if provided
if (tweaks && (typeof tweaks !== 'object' || Array.isArray(tweaks))) {
  return [{ json: { valid: false, error: 'tweaks must be an object if provided' } }];
}

// Validate refresh_langchain_cache is a boolean if provided
if (refreshLangchainCache !== undefined && typeof refreshLangchainCache !== 'boolean') {
  return [{ json: { valid: false, error: 'refresh_langchain_cache must be a boolean if provided' } }];
}

return [{
  json: {
    valid: true,
    flowId: flowId,
    inputs: inputs,
    stream: stream,
    flowName: flowName,
    logLevel: logLevel,
    tweaks: tweaks,
    refresh_langchain_cache: refreshLangchainCache
  }
}];

